import React, { useState } from "react";
import FormKredit from "./components/FormKredit";
import HasilKalkulasi from "./components/HasilKalkulasi";
import TabelJadwal from "./components/TabelJadwal";
import {
  getBunga,
  hitungDP,
  hitungPokokUtang,
  hitungAngsuranPerBulan,
  generateJadwalAngsuran,
  validateForm,
} from "./utils/kreditUtils";
import "./App.css";

/**
 * App — root component aplikasi kalkulator kredit IMS Finance.
 *
 * State yang dikelola:
 * - form    : nilai-nilai input dari user
 * - errors  : hasil validasi per field
 * - result  : hasil kalkulasi (null sebelum submit)
 */
function App() {
  // ── State form — diisi dengan data default contoh soal ──────────
  const [form, setForm] = useState({
    kontrak_no: "AGR00001",
    client_name: "SUGUS",
    otr: "240000000",       // Rp 240.000.000
    dp_pct: "20",           // 20%
    jangka: "18",           // 18 bulan = 1,5 tahun
    start_date: "2024-01-25",
  });

  // ── State error validasi ────────────────────────────────────────
  const [errors, setErrors] = useState({});

  // ── State hasil kalkulasi (null = belum dihitung) ───────────────
  const [result, setResult] = useState(null);

  /**
   * Handler perubahan input.
   * Setiap kali user mengetik, update state form & reset result.
   */
  function handleChange(e) {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
    // Reset hasil agar tidak menampilkan data lama
    setResult(null);
  }

  /**
   * Handler submit form.
   * Urutan: validasi → kalkulasi → set result
   */
  function handleSubmit() {
    // 1. Validasi semua field
    const validationErrors = validateForm(form);

    if (Object.keys(validationErrors).length > 0) {
      // Ada error → simpan ke state, hentikan proses
      setErrors(validationErrors);
      return;
    }

    // 2. Bersihkan error lama
    setErrors({});

    // 3. Konversi string input ke number
    const otr = Number(form.otr);
    const dpPct = Number(form.dp_pct);
    const jangka = Number(form.jangka);

    // 4. Jalankan kalkulasi sesuai flowchart soal
    const dp = hitungDP(otr, dpPct);
    const pokok = hitungPokokUtang(otr, dp);
    const { rate, label: rateLabel } = getBunga(jangka);
    const angsuran = hitungAngsuranPerBulan(pokok, rate, jangka);
    const totalBunga = pokok * rate;
    const totalBayar = angsuran * jangka;

    // 5. Generate tabel jadwal angsuran
    const jadwal = generateJadwalAngsuran(
      form.kontrak_no,
      angsuran,
      jangka,
      form.start_date
    );

    // 6. Simpan semua hasil ke state
    setResult({
      otr,
      dp,
      pokok,
      jangka,
      rate,
      rateLabel,
      angsuran,
      totalBunga,
      totalBayar,
      jadwal,
    });
  }

  return (
    <div className="app-container">
      {/* ── Header Aplikasi ── */}
      <header className="app-header">
        <div className="header-logo">IMS</div>
        <div>
          <h1 className="app-title">IMS Finance</h1>
          <p className="app-subtitle">Kalkulator Kredit Kendaraan</p>
        </div>
      </header>

      <main className="app-main">
        {/* ── Form Input ── */}
        <FormKredit
          form={form}
          errors={errors}
          onChange={handleChange}
          onSubmit={handleSubmit}
        />

        {/* ── Hasil Kalkulasi — hanya tampil setelah submit ── */}
        {result && (
          <>
            <HasilKalkulasi result={result} dpPct={form.dp_pct} />
            <TabelJadwal jadwal={result.jadwal} totalBayar={result.totalBayar} />
          </>
        )}
      </main>

      <footer className="app-footer">
        © 2024 PT. Inovasi Mitra Sejati — CONFIDENTIAL
      </footer>
    </div>
  );
}

export default App;
